  Artigo 221.º 
Início do concurso de concepção
                            
                           
                             
                               
                             
     (Revogado.)            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - DL n.º 111-B/2017, de 31 de Agosto
  Versões anteriores deste artigo:    - 1ª versão: DL n.º 18/2008, de 29 de Janeiro   
     
                         
                          
  Artigo 222.º 
Decisão de escolha da modalidade do concurso de concepção
                            
                           
                             
                               
                             
     (Revogado.)            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - DL n.º 111-B/2017, de 31 de Agosto
  Versões anteriores deste artigo:    - 1ª versão: DL n.º 18/2008, de 29 de Janeiro   
     
                         
                          
  Artigo 223.º 
Agrupamento de entidades adjudicantes
                            
                           
                             
                               
                             
     (Revogado.)            
         
  Cont','32');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('ém as alterações introduzidas pelos seguintes diplomas:   - DL n.º 111-B/2017, de 31 de Agosto
  Versões anteriores deste artigo:    - 1ª versão: DL n.º 18/2008, de 29 de Janeiro   
     
                         
                          
  Artigo 224.º 
