INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('n.º 99-A/2021, de 31 de Dezembro
  Versões anteriores deste artigo:    - 1ª versão: DL n.º 486/99, de 13 de Novembro    - 2ª versão: DL n.º 52/2006, de 15 de Março    - 3ª versão: Lei n.º 35/2018, de 20 de Julho   
     
                         
                          
